PRAGMA defer_foreign_keys=TRUE;
CREATE TABLE users (
  id                TEXT PRIMARY KEY,          -- UUID
  email             TEXT UNIQUE NOT NULL,
  name              TEXT,
  google_id         TEXT UNIQUE,
  subscription_tier TEXT DEFAULT 'free',       -- 'free' | 'basic' | 'premium'
  notification_email TEXT,                    -- Email nhận báo cáo tuần
  created_at        INTEGER DEFAULT (unixepoch())
, is_admin INTEGER DEFAULT 0);
CREATE TABLE student_profiles (
  id           TEXT PRIMARY KEY,              -- UUID
  user_id      TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  display_name TEXT NOT NULL,
  avatar_id    TEXT DEFAULT 'cat',            -- key từ kho avatar preset
  theme        TEXT DEFAULT 'purple',         -- 'purple'|'ocean'|'sakura'|'forest'|'night'|'sunset'
  created_at   INTEGER DEFAULT (unixepoch())
, current_grade INTEGER DEFAULT NULL, selected_pathway TEXT DEFAULT NULL);
CREATE TABLE student_stats (
  student_id        TEXT PRIMARY KEY REFERENCES student_profiles(id) ON DELETE CASCADE,
  total_stars       INTEGER DEFAULT 0,
  current_streak    INTEGER DEFAULT 0,
  longest_streak    INTEGER DEFAULT 0,
  total_sessions    INTEGER DEFAULT 0,
  last_active       INTEGER,
  -- Skill levels per part (0–5 scale)
  lvl_listening_p1  INTEGER DEFAULT 0,
  lvl_listening_p2  INTEGER DEFAULT 0,
  lvl_listening_p3  INTEGER DEFAULT 0,
  lvl_listening_p4  INTEGER DEFAULT 0,
  lvl_reading_p1    INTEGER DEFAULT 0,
  lvl_reading_p2    INTEGER DEFAULT 0,
  lvl_reading_p3    INTEGER DEFAULT 0,
  lvl_reading_p4    INTEGER DEFAULT 0,
  lvl_writing_p1    INTEGER DEFAULT 0,
  preferences_json  TEXT DEFAULT '{}'         -- theme, sound on/off, v.v.
);
CREATE TABLE dream_goals (
  id               TEXT PRIMARY KEY,          -- UUID
  student_id       TEXT NOT NULL REFERENCES student_profiles(id) ON DELETE CASCADE,
  exam_id          TEXT NOT NULL,             -- 'flyers' | 'movers' | 'ket'
  goal_type        TEXT NOT NULL,             -- 'stars' | 'shields' | 'complete'
  goal_target      INTEGER NOT NULL,
  reward_label     TEXT NOT NULL,             -- "Du lịch Đà Nẵng"
  reward_image_key TEXT,                      -- preset key hoặc R2 path
  status           TEXT DEFAULT 'pending',    -- 'pending'|'approved'|'rejected'|'achieved'
  approval_token   TEXT UNIQUE,               -- token trong email link (UUID)
  token_expires    INTEGER,                   -- unixepoch, hạn 7 ngày
  current_progress INTEGER DEFAULT 0,
  approved_at      INTEGER,
  achieved_at      INTEGER,
  created_at       INTEGER DEFAULT (unixepoch())
);
CREATE TABLE quiz_attempts (
  id                   TEXT PRIMARY KEY,      -- UUID
  student_id           TEXT NOT NULL REFERENCES student_profiles(id) ON DELETE CASCADE,
  quiz_id              TEXT NOT NULL,         -- ID bài JSON (vd: 'L001', 'RW002')
  skill                TEXT NOT NULL,         -- 'listening' | 'reading' | 'writing'
  part_number          INTEGER,               -- 1, 2, 3, 4
  score                INTEGER,               -- số câu đúng
  max_score            INTEGER,               -- tổng số câu
  stars_earned         INTEGER DEFAULT 0,     -- ⭐ nhận được (dựa trên % + bonus)
  answers_json         TEXT,                  -- {"q1": "a", "q2": "c"}
  time_spent           INTEGER,               -- giây
  is_challenge         INTEGER DEFAULT 0,     -- 0=normal | 1=challenge mode
  challenge_threshold  INTEGER,               -- 80 = phải đạt ≥ 80%
  challenge_multiplier REAL DEFAULT 1.0,      -- 2.0 = gấp đôi sao
  stars_base           INTEGER DEFAULT 0,     -- sao trước bonus
  completed_at         INTEGER DEFAULT (unixepoch())
, pathway TEXT DEFAULT NULL, subject TEXT DEFAULT NULL, is_free INTEGER DEFAULT 1);
CREATE TABLE daily_activity (
  student_id TEXT NOT NULL REFERENCES student_profiles(id) ON DELETE CASCADE,
  date_key   TEXT NOT NULL,                   -- 'YYYY-MM-DD'
  sessions   INTEGER DEFAULT 0,
  stars      INTEGER DEFAULT 0,
  PRIMARY KEY (student_id, date_key)
);
CREATE TABLE subscriptions (
  id          TEXT PRIMARY KEY,              -- UUID
  user_id     TEXT NOT NULL REFERENCES users(id) ON DELETE CASCADE,
  plan        TEXT NOT NULL,                 -- 'basic' | 'premium' | 'family'
  expires_at  INTEGER NOT NULL,              -- unixepoch
  payment_ref TEXT,                          -- PayOS reference
  created_at  INTEGER DEFAULT (unixepoch())
);
CREATE TABLE quiz_configs (
  quiz_id      TEXT PRIMARY KEY,
  is_free      INTEGER DEFAULT 0,      -- 0=premium, 1=free
  is_published INTEGER DEFAULT 1,      -- 0=draft, 1=published
  sort_order   INTEGER DEFAULT 0,
  created_at   INTEGER DEFAULT (unixepoch()),
  updated_at   INTEGER DEFAULT (unixepoch())
);
CREATE TABLE vocabulary_bank (  id              TEXT PRIMARY KEY,  word            TEXT NOT NULL,  translation_vi  TEXT NOT NULL,  ipa             TEXT,  word_type       TEXT,  example_en      TEXT,  example_vi      TEXT,  subject         TEXT NOT NULL DEFAULT 'english',  group_tag       TEXT NOT NULL DEFAULT 'flyers',  level_order     INTEGER NOT NULL DEFAULT 3,  topic           TEXT,  difficulty      TEXT DEFAULT 'medium',  game_hangman    INTEGER DEFAULT 1,  game_flashcard  INTEGER DEFAULT 1,  game_choice     INTEGER DEFAULT 1,  is_active       INTEGER DEFAULT 1,  created_at      INTEGER DEFAULT (unixepoch()), certificate TEXT NOT NULL DEFAULT 'flyers', cert_order INTEGER NOT NULL DEFAULT 3, image_url TEXT, audio_url TEXT, emoji TEXT);
CREATE TABLE d1_migrations(
		id         INTEGER PRIMARY KEY AUTOINCREMENT,
		name       TEXT UNIQUE,
		applied_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP NOT NULL
);
CREATE TABLE student_vocabulary (
  id              INTEGER PRIMARY KEY AUTOINCREMENT,
  student_id      TEXT NOT NULL,
  word_id         TEXT NOT NULL,
  mastery_level   INTEGER NOT NULL DEFAULT 0,
  
  
  

  correct_count   INTEGER NOT NULL DEFAULT 0,
  seen_count      INTEGER NOT NULL DEFAULT 0,

  
  interval_days   INTEGER NOT NULL DEFAULT 1,
  
  

  next_review_at  INTEGER,
  
  
  

  last_seen_at    INTEGER,
  first_seen_at   INTEGER DEFAULT (unixepoch()),

  UNIQUE(student_id, word_id)
  
);
DELETE FROM sqlite_sequence;
CREATE INDEX idx_student_profiles_user ON student_profiles(user_id);
CREATE INDEX idx_dream_goals_student ON dream_goals(student_id, status);
CREATE INDEX idx_dream_goals_token ON dream_goals(approval_token) WHERE approval_token IS NOT NULL;
CREATE INDEX idx_quiz_attempts_student ON quiz_attempts(student_id, completed_at DESC);
CREATE INDEX idx_quiz_attempts_skill   ON quiz_attempts(student_id, skill, part_number);
CREATE INDEX idx_quiz_attempts_quiz    ON quiz_attempts(quiz_id);
CREATE INDEX idx_subscriptions_user ON subscriptions(user_id, expires_at DESC);
CREATE INDEX idx_quiz_configs_free ON quiz_configs(is_free, is_published);
CREATE INDEX idx_quiz_configs_order ON quiz_configs(sort_order);
CREATE INDEX idx_vocab_group   ON vocabulary_bank(group_tag, level_order);
CREATE INDEX idx_vocab_subject ON vocabulary_bank(subject, difficulty);
CREATE INDEX idx_vocab_topic   ON vocabulary_bank(topic);
CREATE INDEX idx_quiz_attempts_pathway_subject
  ON quiz_attempts(student_id, pathway, subject, completed_at DESC);
CREATE INDEX idx_vocab_cert    ON vocabulary_bank(certificate, cert_order);
CREATE INDEX idx_vocab_lesson  ON vocabulary_bank(topic, cert_order, is_active);
CREATE INDEX idx_sv_student_word
  ON student_vocabulary(student_id, word_id);
CREATE INDEX idx_sv_review
  ON student_vocabulary(student_id, next_review_at);
CREATE INDEX idx_sv_mastery
  ON student_vocabulary(student_id, mastery_level);
